import hashlib

def calculate_file_hash(file_path):
    try:
        with open(file_path, 'rb') as f:
            hash = hashlib.sha256()
            while chunk := f.read(4096):
                hash.update(chunk)
            return hash.hexdigest()
    except Exception as e:
        print(f"Error calculating file hash: {e}")
        return None